// Per-channel retention policies
// retentionDays: messages older than this get archived
// archiveSchedule: 'weekly' or 'monthly'
// enabled: toggle per channel
const RETENTION_POLICIES = [
  {
    channelId: 'REPLACE_GENERAL_CHANNEL_ID',
    channelName: 'general',
    retentionDays: 90,
    enabled: true
  },
  {
    channelId: 'REPLACE_IT_CHANNEL_ID',
    channelName: 'it',
    retentionDays: 180, // keep IT longer
    enabled: true
  },
  {
    channelId: 'REPLACE_RANDOM_CHANNEL_ID',
    channelName: 'random',
    retentionDays: 30, // short retention for casual
    enabled: true
  }
  // Add more channels as needed
];

const now = Date.now();
const results = [];

for (const policy of RETENTION_POLICIES) {
  if (!policy.enabled) continue;

  const cutoffTs = Math.floor((now - policy.retentionDays * 86400000) / 1000);
  const cutoffDate = new Date(cutoffTs * 1000).toISOString().split('T')[0];

  results.push({
    json: {
      channelId: policy.channelId,
      channelName: policy.channelName,
      retentionDays: policy.retentionDays,
      cutoffTs: cutoffTs.toString(),
      cutoffDate,
      oldest: '0', // from beginning of time
      latest: cutoffTs.toString()
    }
  });
}

return results;

const items = $input.all();
const results = [];
let totalArchived = 0;

for (const item of items) {
  const messages = item.json.messages || [];
  const channelName = item.json.channelName;
  const cutoffDate = item.json.cutoffDate;
  const retentionDays = item.json.retentionDays;

  if (messages.length === 0) continue;

  totalArchived += messages.length;

  const archiveLines = messages.map(msg => JSON.stringify({
    ts: msg.ts,
    user: msg.user || msg.bot_id || 'unknown',
    text: msg.text || '',
    type: msg.type || 'message',
    subtype: msg.subtype || null,
    thread_ts: msg.thread_ts || null
  }));

  const today = new Date().toISOString().split('T')[0];
  const fileName = `${channelName}_retention_before_${cutoffDate}.jsonl`;
  const folderPath = `Slack-Archive/${channelName}/retention`;

  results.push({
    json: {
      channelName,
      fileName,
      folderPath,
      messageCount: messages.length,
      retentionDays,
      cutoffDate,
      archiveDate: today
    },
    binary: {
      data: {
        data: Buffer.from(archiveLines.join('\n'), 'utf-8').toString('base64'),
        mimeType: 'application/jsonl',
        fileName
      }
    }
  });
}

// Summary
results.push({
  json: {
    _isSummary: true,
    totalArchived,
    channelsProcessed: results.length,
    date: new Date().toISOString().split('T')[0]
  }
});

return results;
